import re
import json
import time
from typing import Dict, Any, List, Set, Tuple
import pytest

# =====================================================================
# Constants, Registries, and Regex Patterns
# =====================================================================

# Target Response Time SLAs (in seconds)
SLA_STARTUP_LIMIT_SEC = 15.0
SLA_ENTERPRISE_LIMIT_SEC = 45.0

# Regex to check if text ends with proper terminal punctuation (including quotes or brackets)
TERMINAL_PUNCTUATION_REGEX = re.compile(r'[.!?)"\u201d\u2019]$')

# Common truncation placeholders generated by LLMs or parsers when hitting limits
TRUNCATION_PLACEHOLDERS = ["...", "[truncated]", "read more", "etc.", "etc", ".."]

# Standard dictionary terms and generic English stop words to exclude from signature checks
COMMON_STOP_WORDS = {
    "and", "the", "for", "with", "from", "company", "inc", "corp", "llc", "global", 
    "technologies", "services", "solutions", "limited", "incorporated", "private", 
    "public", "systems", "group", "co", "management", "industries", "partner"
}


# =====================================================================
# Performance Simulation, Truncation, and Context Isolation Functions
# =====================================================================

def simulate_extraction_and_validation(record: Dict[str, Any]) -> Dict[str, Any]:
    """
    Simulates the pipeline extraction, reasoning, and validation of parameters.
    The simulated processing time varies depending on company size, ownership,
    and overall data density.
    """
    # Baseline overhead representing parsing, regex checks, and schema validation
    processing_time = 2.0  
    
    category = record.get("Category", "Startup")
    nature = record.get("Nature of Company", "Private")
    
    # Model higher data density scaling factors
    if category == "Enterprise":
        processing_time += 15.0  # Simulated parsing of dense financial reports
    if nature == "Public":
        processing_time += 10.0  # Simulated query latencies for registries
    if category == "Conglomerate":
        processing_time += 8.0   # Handling complex subsidiaries
        
    # Introduce the simulated processing sleep
    time.sleep(processing_time)
    
    # Return processed record with execution statistics
    record["generation_time_sec"] = processing_time
    record["status"] = "PROCESSED"
    return record


def validate_token_limit_and_truncation(record: Dict[str, Any]) -> bool:
    """
    Evaluates the record to verify that long content has not 
    suffered mid-sentence cutoffs, structural JSON truncation, or trailing parameter drops.
    """
    overview = record.get("Overview of the Company")
    office_locations = record.get("Office Locations")
    ethical_standards = record.get("Ethical standards")  # Schema-end field to verify no drops

    # 1. Validate Narrative Completion (Overview)
    if overview is not None:
        overview_str = str(overview).strip()
        
        # Check for trailing truncation markers
        for placeholder in TRUNCATION_PLACEHOLDERS:
            if overview_str.lower().endswith(placeholder):
                raise ValueError(
                    f"Truncation Detected: 'Overview of the Company' ends with "
                    f"a truncation placeholder '{placeholder}'."
                )
                
        # Check for grammatical completion (must end with terminal punctuation)
        if not TERMINAL_PUNCTUATION_REGEX.search(overview_str):
            raise ValueError(
                f"Grammatical Cutoff Detected: 'Overview of the Company' does not end with "
                f"valid terminal punctuation. Text ends with: '...{overview_str[-20:]}'"
            )

    # 2. Validate Composite Structured Completeness (Office Locations)
    if office_locations is not None:
        locs_str = str(office_locations).strip()
        
        # If expected to be structured JSON, verify it parses cleanly
        if locs_str.startswith("[") or locs_str.startswith("{"):
            try:
                json.loads(locs_str)
            except json.JSONDecodeError as e:
                raise ValueError(
                    f"Structural Truncation Detected: 'Office Locations' failed JSON parsing. "
                    f"It was likely cut off mid-payload. Parsing error: {e}"
                )
        else:
            # For list strings, verify there are no trailing unclosed elements or hanging commas
            if locs_str.endswith(",") or locs_str.endswith("-") or locs_str.endswith("*"):
                raise ValueError(
                    f"Structural Truncation Detected: 'Office Locations' ends with "
                    f"a hanging separator, indicating incomplete list rendering."
                )

    # 3. Validate Schema Preservation (No trailing parameter drops)
    if not ethical_standards:
         raise ValueError(
             "Schema Preservation Error: Tail-end parameter 'Ethical standards' is missing. "
             "The system may have hit a token ceiling and dropped the end of the schema payload."
         )

    return True


def extract_unique_signatures(record: Dict[str, Any]) -> Set[str]:
    """
    Extracts highly specific, lowercase alphanumeric word tokens from a record.
    These tokens serve as the 'data footprint' of the company to detect context leaks.
    """
    signatures: Set[str] = set()
    
    # Target fields that hold highly entity-specific data
    target_fields = [
        "Company Name", "Short Name", "Website URL", "CEO Name", 
        "Company Headquarters", "Key Investors / Backers"
    ]
    
    for field in target_fields:
        val = record.get(field)
        if val:
            # Tokenize and clean the text values
            words = re.findall(r"\b[a-zA-Z]{3,20}\b", str(val).lower())
            for word in words:
                if word not in COMMON_STOP_WORDS:
                    signatures.add(word)
                    
    return signatures


def detect_memory_contamination(company_a: Dict[str, Any], company_b: Dict[str, Any]) -> None:
    """
    Asserts that no highly unique signature tokens from Company A's profile 
    exist in Company B's profile, validating context isolation.
    """
    signatures_a = extract_unique_signatures(company_a)
    
    # Concatenate all values of Company B to search for leakages
    all_b_text = " ".join([str(v) for v in company_b.values() if v is not None]).lower()
    
    # Check for leaks
    leaked_tokens = []
    for token in signatures_a:
        # Enforce boundary checking so standard substrings aren't flagged as leaks
        pattern = re.compile(rf"\b{token}\b")
        if pattern.search(all_b_text):
            leaked_tokens.append(token)
            
    if leaked_tokens:
        raise ValueError(
            f"Memory Contamination Leak Detected: Unique tokens {leaked_tokens} from "
            f"'{company_a.get('Company Name')}' leaked into the record of "
            f"'{company_b.get('Company Name')}'."
        )


